import{_ as i,o as a,c as t,a2 as e}from"./chunks/framework.jWxB9oXr.js";const c=JSON.parse('{"title":"Migrate from Chalk","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Migrate from Chalk"}],["meta",{"property":"og:description","content":"Migrate from Chalk — get up and running with Silvery in minutes."}],["meta",{"property":"og:url","content":"https://silvery.dev/getting-started/migrate-from-chalk.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/getting-started/migrate-from-chalk.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Getting Started\\",\\"item\\":\\"https://silvery.dev/getting-started\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Migrate from Chalk\\",\\"item\\":\\"https://silvery.dev/getting-started/migrate-from-chalk\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Migrate from Chalk\\",\\"description\\":\\"Migrate from Chalk — get up and running with Silvery in minutes.\\",\\"url\\":\\"https://silvery.dev/getting-started/migrate-from-chalk.html\\",\\"dateModified\\":\\"2026-03-25T19:04:51.000Z\\",\\"datePublished\\":\\"2026-03-25T19:04:51.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"getting-started/migrate-from-chalk.md","filePath":"getting-started/migrate-from-chalk.md","lastUpdated":1774465491000}'),l={name:"getting-started/migrate-from-chalk.md"};function n(h,s,r,p,o,d){return a(),t("div",null,[...s[0]||(s[0]=[e(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /getting-started/migrate-from-chalk.md for this page in Markdown format</div><h1 id="migrate-from-chalk" tabindex="-1">Migrate from Chalk <a class="header-anchor" href="#migrate-from-chalk" aria-label="Permalink to &quot;Migrate from Chalk&quot;">​</a></h1><h2 id="you-don-t-have-to-migrate" tabindex="-1">You Don&#39;t Have to Migrate <a class="header-anchor" href="#you-don-t-have-to-migrate" aria-label="Permalink to &quot;You Don&#39;t Have to Migrate&quot;">​</a></h2><p>Silvery includes a full Chalk compatibility layer. Just swap the import:</p><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- import chalk from &#39;chalk&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ import chalk from &#39;silvery/chalk&#39;</span></span></code></pre></div><p>That&#39;s it. All your chalk-styled strings work unchanged — <code>chalk.red.bold(&quot;Error!&quot;)</code> produces the same output. You get silvery&#39;s theme-aware color detection for free.</p><p>When you&#39;re ready for silvery&#39;s native styling (semantic tokens, theme palettes, auto-dark/light), follow the steps below.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><h3 id="step-1-install-silvery" tabindex="-1">Step 1: Install Silvery <a class="header-anchor" href="#step-1-install-silvery" aria-label="Permalink to &quot;Step 1: Install Silvery&quot;">​</a></h3><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-lc5Pb" id="tab-fwsQAfs" checked><label data-title="bun" for="tab-fwsQAfs">bun</label><input type="radio" name="group-lc5Pb" id="tab-C1Jkv0r"><label data-title="npm" for="tab-C1Jkv0r">npm</label><input type="radio" name="group-lc5Pb" id="tab-pK0aq83"><label data-title="pnpm" for="tab-pK0aq83">pnpm</label><input type="radio" name="group-lc5Pb" id="tab-6HXY9vJ"><label data-title="yarn" for="tab-6HXY9vJ">yarn</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> silvery</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> silvery</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> silvery</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> silvery</span></span></code></pre></div></div></div><h3 id="step-2-update-imports" tabindex="-1">Step 2: Update Imports <a class="header-anchor" href="#step-2-update-imports" aria-label="Permalink to &quot;Step 2: Update Imports&quot;">​</a></h3><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- import chalk from &#39;chalk&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ import chalk from &#39;silvery/chalk&#39;</span></span></code></pre></div><p>The <code>silvery/chalk</code> module provides a Chalk-compatible API. Your existing chalk-styled strings work unchanged inside Silvery&#39;s <code>&lt;Text&gt;</code> component:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chalk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery/chalk&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Text } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Chalk-style strings work inside Text</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{chalk.red.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Error!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)}&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Or use Text&#39;s built-in style props directly</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;red&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Error!&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="api-compatibility" tabindex="-1">API Compatibility <a class="header-anchor" href="#api-compatibility" aria-label="Permalink to &quot;API Compatibility&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chalk Feature</th><th>silvery/chalk</th><th>Notes</th></tr></thead><tbody><tr><td><code>chalk.red()</code></td><td>Supported</td><td>All standard colors</td></tr><tr><td><code>chalk.bold()</code></td><td>Supported</td><td>All modifiers</td></tr><tr><td><code>chalk.rgb()</code></td><td>Supported</td><td>24-bit color</td></tr><tr><td><code>chalk.hex()</code></td><td>Supported</td><td>Hex color codes</td></tr><tr><td><code>chalk.bgRed()</code></td><td>Supported</td><td>Background colors</td></tr><tr><td>Chaining</td><td>Supported</td><td><code>chalk.red.bold.underline()</code></td></tr><tr><td>Template literals</td><td>Supported</td><td><code>chalk\`{red text}\`</code></td></tr></tbody></table><h2 id="why-switch" tabindex="-1">Why Switch? <a class="header-anchor" href="#why-switch" aria-label="Permalink to &quot;Why Switch?&quot;">​</a></h2><ul><li><strong>Zero dependencies</strong> -- Silvery&#39;s chalk compat is built-in, no extra package needed</li><li><strong>ANSI-aware compositing</strong> -- Pre-styled text composes correctly with layout and styles (see below)</li><li><strong>Consistent theming</strong> -- Use <code>$token</code> colors from <code>@silvery/theme</code> alongside chalk-style strings</li><li><strong>Tree-shakeable</strong> -- Only the styles you use end up in your bundle</li></ul><h2 id="ansi-aware-compositing" tabindex="-1">ANSI-Aware Compositing <a class="header-anchor" href="#ansi-aware-compositing" aria-label="Permalink to &quot;ANSI-Aware Compositing&quot;">​</a></h2><p>Most terminal frameworks pass <a href="https://terminfo.dev/fundamentals/anatomy" class="hover-link" data-tooltip="Control codes starting with ESC that tell terminals to set colors, move cursor, etc." target="_blank" rel="noopener">ANSI escape</a> sequences through as opaque strings. This breaks when styled text meets layout — clipping mid-sequence corrupts terminal state, backgrounds don&#39;t cascade through styled text, and <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> can&#39;t diff styled regions.</p><p>Silvery parses all ANSI sequences (from chalk, kleur, picocolors, or raw escapes) into structured cell properties, then reconstructs optimal output during rendering. This means pre-styled text participates fully in layout, composition, and diffing:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chalk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery/chalk&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Chalk styles compose with Silvery&#39;s component styles</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> backgroundColor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;blue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{chalk.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)} and {chalk.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yellow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;warning&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)}&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Result: &quot;error&quot; is red+bold on blue, &quot;warning&quot; is yellow+bold on blue</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// The blue background cascades through chalk-styled text automatically</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Styles merge at the cell level — no leaked resets, no conflicts</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cyan&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> underline</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {chalk.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold+cyan+underline&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)} just cyan+underline</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>With raw passthrough (<a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>, blessed), the same code produces broken output — chalk&#39;s reset sequences (<code>\\x1b[39m</code>) clear the parent&#39;s background, clipping truncates mid-escape-sequence, and unchanged styled text gets re-emitted every frame.</p><p>See <a href="/guide/ansi-layering.html">Smart ANSI Layering</a> for the full architecture.</p><h2 id="using-theme-colors-instead" tabindex="-1">Using Theme Colors Instead <a class="header-anchor" href="#using-theme-colors-instead" aria-label="Permalink to &quot;Using Theme Colors Instead&quot;">​</a></h2><p>For new code, consider using Silvery&#39;s semantic theme tokens instead of hardcoded colors:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Text, ThemeProvider } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { presetTheme } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@silvery/theme&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Instead of chalk.red(&quot;Error&quot;)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Error!&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Instead of chalk.dim(&quot;secondary text&quot;)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$muted&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Secondary text&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>Theme tokens adapt to the active palette -- your app looks correct in any theme without changing color values.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guides/theming.html">Theming Guide</a> -- Full theme system documentation</li><li><a href="/guides/components.html">Components Guide</a> -- <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> component styling props</li><li><a href="/reference/compatibility.html">Ink/Chalk Compatibility Reference</a> -- Complete API mapping tables</li></ul>`,30)])])}const g=i(l,[["render",n]]);export{c as __pageData,g as default};
